# lib/blog/html_sanitizer.ex
defmodule Blog.HtmlSanitizer do
  @moduledoc """
  Sanitizes user-generated HTML content to prevent XSS attacks
  while allowing safe rich-text formatting tags.
  """

  # Define a custom scrubber that allows safe HTML tags and attributes
  # but strips out dangerous elements like <script>, event handlers, etc.
  defmodule SafeHtmlScrubber do
    require HtmlSanitizeEx.Scrubber.Meta
    alias HtmlSanitizeEx.Scrubber.Meta

    # Allow safe text formatting tags
    @allowed_tags ~w(
      p br div span
      h1 h2 h3 h4 h5 h6
      strong em b i u s strike del ins
      ul ol li
      blockquote pre code
      a img
      table thead tbody tr th td
      hr sub sup
      figure figcaption
    )

    # Allow safe attributes per tag
    @allowed_attributes_global ~w(class id title)

    Meta.remove_cdata_sections_before_scrub()
    Meta.strip_comments()

    # Strip all script, style, iframe, object, embed, form tags entirely
    Meta.strip_everything_not_covered()

    # Allow text nodes
    def scrub({:text, text}), do: {:text, text}

    # Allow specific tags with filtered attributes
    for tag <- @allowed_tags do
      def scrub({unquote(tag), attributes, children}) do
        {unquote(tag), scrub_attributes(unquote(tag), attributes), children}
      end
    end

    # Strip any tag not in the allowed list
    def scrub({_tag, _attributes, children}), do: children
    def scrub(other), do: other

    # Attribute filtering per tag
    defp scrub_attributes("a", attributes) do
      attributes
      |> Enum.filter(fn {attr, _val} -> attr in (@allowed_attributes_global ++ ~w(href rel target)) end)
      |> sanitize_href()
      |> enforce_safe_link_attributes()
    end

    defp scrub_attributes("img", attributes) do
      attributes
      |> Enum.filter(fn {attr, _val} -> attr in (@allowed_attributes_global ++ ~w(src alt width height loading)) end)
      |> sanitize_src()
    end

    defp scrub_attributes("td", attributes) do
      attributes
      |> Enum.filter(fn {attr, _val} -> attr in (@allowed_attributes_global ++ ~w(colspan rowspan)) end)
    end

    defp scrub_attributes("th", attributes) do
      attributes
      |> Enum.filter(fn {attr, _val} -> attr in (@allowed_attributes_global ++ ~w(colspan rowspan)) end)
    end

    defp scrub_attributes(_tag, attributes) do
      attributes
      |> Enum.filter(fn {attr, _val} -> attr in @allowed_attributes_global end)
    end

    # Prevent javascript: URIs in href attributes
    defp sanitize_href(attributes) do
      Enum.map(attributes, fn
        {"href", value} ->
          cleaned = String.trim(value)

          if safe_url?(cleaned) do
            {"href", cleaned}
          else
            {"href", "#"}
          end

        other ->
          other
      end)
    end

    # Prevent javascript: URIs in src attributes
    defp sanitize_src(attributes) do
      Enum.map(attributes, fn
        {"src", value} ->
          cleaned = String.trim(value)

          if safe_url?(cleaned) do
            {"src", cleaned}
          else
            {"src", ""}
          end

        other ->
          other
      end)
    end

    # Only allow http, https, mailto, and relative URLs
    defp safe_url?(url) do
      lowercase = String.downcase(url)

      cond do
        String.starts_with?(lowercase, "http://") -> true
        String.starts_with?(lowercase, "https://") -> true
        String.starts_with?(lowercase, "mailto:") -> true
        String.starts_with?(lowercase, "/") -> true
        String.starts_with?(lowercase, "#") -> true
        # Block javascript:, data:, vbscript:, etc.
        String.contains?(lowercase, ":") -> false
        true -> true
      end
    end

    # Force links to open safely
    defp enforce_safe_link_attributes(attributes) do
      attributes
      |> Enum.reject(fn {attr, _} -> attr in ~w(rel target) end)
      |> Kernel.++([{"rel", "noopener noreferrer nofollow"}, {"target", "_blank"}])
    end
  end

  @doc """
  Sanitizes HTML content, removing dangerous tags and attributes
  while preserving safe formatting.

  ## Examples

      iex> Blog.HtmlSanitizer.sanitize("<p>Hello</p><script>alert('xss')</script>")
      "<p>Hello</p>"

      iex> Blog.HtmlSanitizer.sanitize("<a href=\"javascript:alert(1)\">click</a>")
      "<a href=\"#\" rel=\"noopener noreferrer nofollow\" target=\"_blank\">click</a>"
  """
  @spec sanitize(String.t() | nil) :: String.t()
  def sanitize(nil), do: ""
  def sanitize(""), do: ""

  def sanitize(html) when is_binary(html) do
    HtmlSanitizeEx.Scrubber.scrub(html, SafeHtmlScrubber)
  end
end

# lib/blog/posts/post.ex
defmodule Blog.Posts.Post do
  use Ecto.Schema
  import Ecto.Changeset

  schema "posts" do
    field :title, :string
    field :content, :string
    field :sanitized_content, :string
    belongs_to :user, Blog.Accounts.User

    timestamps()
  end

  def changeset(post, attrs) do
    post
    |> cast(attrs, [:title, :content])
    |> validate_required([:title, :content])
    |> validate_length(:title, max: 255)
    |> validate_length(:content, max: 100_000)
    |> sanitize_content()
  end

  # Sanitize content at write time so it's stored clean
  defp sanitize_content(changeset) do
    case get_change(changeset, :content) do
      nil ->
        changeset

      content ->
        put_change(changeset, :sanitized_content, Blog.HtmlSanitizer.sanitize(content))
    end
  end
end

# lib/blog_web/live/post_live/show.ex
defmodule BlogWeb.PostLive.Show do
  use BlogWeb, :live_view

  alias Blog.Posts

  @impl true
  def mount(%{"id" => id}, _session, socket) do
    post = Posts.get_post!(id)

    {:ok, assign(socket, :post, post)}
  end

  @impl true
  def render(assigns) do
    ~H"""
    <article class="blog-post">
      <header>
        <h1><%= @post.title %></h1>
        <p class="post-meta">
          Published on <%= Calendar.strftime(@post.inserted_at, "%B %d, %Y") %>
        </p>
      </header>

      <div class="post-content prose">
        <%!--
          SAFE: We render sanitized_content which has been sanitized at write time
          using Blog.HtmlSanitizer. The raw content is preserved in the `content`
          field for editing, but we never render it directly.

          As a defense-in-depth measure, we also sanitize at render time.
        --%>
        <%= raw(sanitize_for_display(@post)) %>
      </div>
    </article>
    """
  end

  # Defense in depth: sanitize again at render time even though
  # content was sanitized at write time
  defp sanitize_for_display(post) do
    content = post.sanitized_content || post.content || ""
    Blog.HtmlSanitizer.sanitize(content)
  end
end

# lib/blog_web/live/post_live/index.ex
defmodule BlogWeb.PostLive.Index do
  use BlogWeb, :live_view

  alias Blog.Posts

  @impl true
  def mount(_params, _session, socket) do
    posts = Posts.list_posts()
    {:ok, assign(socket, :posts, posts)}
  end

  @impl true
  def render(assigns) do
    ~H"""
    <div class="posts-listing">
      <h1>Blog Posts</h1>

      <div :for={post <- @posts} class="post-preview">
        <h2>
          <.link navigate={~p"/posts/#{post.id}"}>
            <%= post.title %>
          </.link>
        </h2>
        <div class="post-excerpt prose">
          <%= raw(truncate_and_sanitize(post)) %>
        </div>
      </div>
    </div>
    """
  end

  defp truncate_and_sanitize(post) do
    content = post.sanitized_content || post.content || ""

    content
    |> Blog.HtmlSanitizer.sanitize()
    |> String.slice(0, 500)
    |> close_open_tags()
  end

  # Simple helper to close any tags left open after truncation
  defp close_open_tags(html) do
    # Use a simple approach: strip tags from truncated content for previews
    # to avoid broken HTML from truncation
    HtmlSanitizeEx.strip_tags(html)
  end
end

# lib/blog_web/live/post_live/form.ex
defmodule BlogWeb.PostLive.Form do
  use BlogWeb, :live_view

  alias Blog.Posts
  alias Blog.Posts.Post

  @impl true
  def mount(params, _session, socket) do
    {post, action} =
      case params do
        %{"id" => id} -> {Posts.get_post!(id), :edit}
        _ -> {%Post{}, :new}
      end

    changeset = Post.changeset(post, %{})

    {:ok,
     socket
     |> assign(:post, post)
     |> assign(:action, action)
     |> assign(:form, to_form(changeset))
     |> assign(:preview_html, nil)}
  end

  @impl true
  def render(assigns) do
    ~H"""
    <div class="post-editor">
      <h1><%= if @action == :new, do: "New Post", else: "Edit Post" %></h1>

      <.form for={@form} phx-change="validate" phx-submit="save">
        <div class="form-group">
          <label for="post_title">Title</label>
          <.input field={@form[:title]} type="text" placeholder="Post title" />
        </div>

        <div class="form-group">
          <label for="post_content">Content (HTML allowed)</label>
          <textarea
            id="post_content"
            name={@form[:content].name}
            rows="20"
            class="w-full font-mono"
            phx-debounce="500"
          ><%= @form[:content].value %></textarea>
          <p class="help-text">
            Allowed tags: p, h1-h6, strong, em, b, i, u, a, img, ul, ol, li,
            blockquote, pre, code, table, hr, br, div, span.
            Script tags and event handlers are stripped for security.
          </p>
        </div>

        <div class="form-actions">
          <button type="submit" class="btn btn-primary">
            <%= if @action == :new, do: "Publish", else: "Update" %>
          </button>
          <button type="button" phx-click="preview" class="btn btn-secondary">
            Preview
          </button>
        </div>
      </.form>

      <%= if @preview_html do %>
        <div class="post-preview-panel">
          <h2>Preview</h2>
          <div class="prose">
            <%!-- Preview is sanitized before being assigned to the socket --%>
            <%= raw(@preview_html) %>
          </div>
        </div>
      <% end %>
    </div>
    """
  end

  @impl true
  def handle_event("validate", %{"post" => post_params}, socket) do
    changeset =
      socket.assigns.post
      |> Post.changeset(post_params)
      |> Map.put(:action, :validate)

    {:noreply, assign(socket, :form, to_form(changeset))}
  end

  @impl true
  def handle_event("preview", _params, socket) do
    content = socket.assigns.form.params["content"] || ""
    # Sanitize before assigning to socket for preview rendering
    sanitized = Blog.HtmlSanitizer.sanitize(content)
    {:noreply, assign(socket, :preview_html, sanitized)}
  end

  @impl true
  def handle_event("save", %{"post" => post_params}, socket) do
    case socket.assigns.action do
      :new ->
        case Posts.create_post(post_params) do
          {:ok, post} ->
            {:noreply,
             socket
             |> put_flash(:info, "Post published successfully!")
             |> push_navigate(to: ~p"/posts/#{post.id}")}

          {:error, changeset} ->
            {:noreply, assign(socket, :form, to_form(changeset))}
        end

      :edit ->
        case Posts.update_post(socket.assigns.post, post_params) do
          {:ok, post} ->
            {:noreply,
             socket
             |> put_flash(:info, "Post updated successfully!")
             |> push_navigate(to: ~p"/posts/#{post.id}")}

          {:error, changeset} ->
            {:noreply, assign(socket, :form, to_form(changeset))}
        end
    end
  end
end

# lib/blog/posts.ex
defmodule Blog.Posts do
  import Ecto.Query
  alias Blog.Repo
  alias Blog.Posts.Post

  def list_posts do
    Post
    |> order_by(desc: :inserted_at)
    |> Repo.all()
  end

  def get_post!(id), do: Repo.get!(Post, id)

  def create_post(attrs) do
    %Post{}
    |> Post.changeset(attrs)
    |> Repo.insert()
  end

  def update_post(%Post{} = post, attrs) do
    post
    |> Post.changeset(attrs)
    |> Repo.update()
  end

  def delete_post(%Post{} = post) do
    Repo.delete(post)
  end
end

# lib/blog_web/components/safe_html_component.ex
defmodule BlogWeb.SafeHtmlComponent do
  @moduledoc """
  A reusable component for rendering sanitized HTML content.
  Use this instead of calling raw() directly throughout the app.
  """
  use Phoenix.Component

  attr :content, :string, required: true
  attr :class, :string, default: "prose"

  def safe_html(assigns) do
    sanitized = Blog.HtmlSanitizer.sanitize(assigns.content || "")
    assigns = assign(assigns, :sanitized, sanitized)

    ~H"""
    <div class={@class}>
      <%= raw(@sanitized) %>
    </div>
    """
  end
end

# test/blog/html_sanitizer_test.exs
defmodule Blog.HtmlSanitizerTest do
  use ExUnit.Case, async: true

  alias Blog.HtmlSanitizer

  describe "sanitize/1" do
    test "allows safe formatting tags" do
      html = "<p><strong>Bold</strong> and <em>italic</em></p>"
      assert HtmlSanitizer.sanitize(html) =~ "<strong>Bold</strong>"
      assert HtmlSanitizer.sanitize(html) =~ "<em>italic</em>"
    end

    test "strips script tags" do
      html = "<p>Hello</p><script>alert('xss')</script>"
      result = HtmlSanitizer.sanitize(html)
      refute result =~ "<script>"
      refute result =~ "alert"
      assert result =~ "<p>Hello</p>"
    end

    test "strips event handler attributes" do
      html = ~s(<p onclick="alert('xss')">Click me</p>)
      result = HtmlSanitizer.sanitize(html)
      refute result =~ "onclick"
      assert result =~ "Click me"
    end

    test "blocks javascript: URIs in href" do
      html = ~s(<a href="javascript:alert(1)">click</a>)
      result = HtmlSanitizer.sanitize(html)
      refute result =~ "javascript:"
      assert result =~ ~s(href="#")
    end

    test "blocks javascript: URIs in img src" do
      html = ~s(<img src="javascript:alert(1)">)
      result = HtmlSanitizer.sanitize(html)
      refute result =~ "javascript:"
    end

    test "allows safe links" do
      html = ~s(<a href="https://example.com">Link</a>)
      result = HtmlSanitizer.sanitize(html)
      assert result =~ "https://example.com"
      assert result =~ "noopener"
      assert result =~ "noreferrer"
      assert result =~ "nofollow"
    end

    test "strips iframe tags" do
      html = ~s(<iframe src="https://evil.com"></iframe>)
      result = HtmlSanitizer.sanitize(html)
      refute result =~ "<iframe"
    end

    test "strips style tags" do
      html = "<style>body { display: none; }</style><p>Content</p>"
      result = HtmlSanitizer.sanitize(html)
      refute result =~ "<style"
      assert result =~ "<p>Content</p>"
    end

    test "handles nil input" do
      assert HtmlSanitizer.sanitize(nil) == ""
    end

    test "handles empty string" do
      assert HtmlSanitizer.sanitize("") == ""
    end

    test "strips data: URIs" do
      html = ~s(<a href="data:text/html,<script>alert(1)</script>">click</a>)
      result = HtmlSanitizer.sanitize(html)
      refute result =~ "data:"
    end

    test "handles encoded javascript URIs" do
      html = ~s(<a href="&#106;avascript:alert(1)">click</a>)
      result = HtmlSanitizer.sanitize(html)
      refute result =~ "javascript"
    end
  end
end